"use client";

import React, { useEffect, useRef } from "react";

// In a real setup, we would import the hook and call it in the parent component
// to lift state up. But for performance (avoiding 60fps React re-renders), 
// we will instantiate the hook entirely inside this component.

interface AudioCanvasProps {
    isListening: boolean;
    smoothing: number;
    sensitivity: number;
    visualStyle: "bars" | "rings" | "particles";
}

// Minimal Audio Data Box definition (mirrored from the hook)
interface AudioDataBox {
    frequencyData: Uint8Array;
    timeDomainData: Uint8Array;
}

export function AudioCanvas(props: AudioCanvasProps) {
    const containerRef = useRef<HTMLDivElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // --- AUDIO LOGIC INLINED FOR EXTREME PERFORMANCE ---
    const analyserRef = useRef<AnalyserNode | null>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const audioCtxRef = useRef<AudioContext | null>(null);

    const audioBoxRef = useRef<AudioDataBox>({
        frequencyData: new Uint8Array(0),
        timeDomainData: new Uint8Array(0),
    });

    // Track particle physics for "particles" mode
    const particlesRef = useRef(Array.from({ length: 150 }, () => ({
        x: 0, y: 0,
        vx: 0, vy: 0,
        size: Math.random() * 4 + 2,
        baseSpeed: Math.random() * 2 + 1,
        angle: Math.random() * Math.PI * 2,
        color: `hsl(${Math.random() * 60 + 200}, 80%, 60%)` // Blue to Purple
    })));

    // Handle stream lifecycle
    useEffect(() => {
        let isMounted = true;

        const start = async () => {
            try {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const AudioContextObj = window.AudioContext || (window as any).webkitAudioContext;
                const ctx = new AudioContextObj();
                audioCtxRef.current = ctx;

                const stream = await navigator.mediaDevices.getUserMedia({
                    audio: { echoCancellation: false, autoGainControl: false, noiseSuppression: false }
                });

                if (!isMounted) {
                    stream.getTracks().forEach(t => t.stop());
                    return;
                }

                streamRef.current = stream;

                const analyser = ctx.createAnalyser();
                analyser.fftSize = 512; // 256 Bins (Lower resolution looks chunkier and better for these visuals)
                analyser.smoothingTimeConstant = props.smoothing;

                const source = ctx.createMediaStreamSource(stream);
                source.connect(analyser);

                analyserRef.current = analyser;
                audioBoxRef.current.frequencyData = new Uint8Array(analyser.frequencyBinCount);
                audioBoxRef.current.timeDomainData = new Uint8Array(analyser.frequencyBinCount);

            } catch (e) {
                console.error("Audio hook failed:", e);
            }
        };

        const stop = () => {
            if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
            if (audioCtxRef.current) audioCtxRef.current.close().catch(console.error);
            analyserRef.current = null;
            audioBoxRef.current.frequencyData.fill(0);
            audioBoxRef.current.timeDomainData.fill(128);
        };

        if (props.isListening) start();
        else stop();

        return () => {
            isMounted = false;
            stop();
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [props.isListening]);

    // Update smoothing dynamically
    useEffect(() => {
        if (analyserRef.current) analyserRef.current.smoothingTimeConstant = props.smoothing;
    }, [props.smoothing]);

    // --- RENDER LOGIC ---
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        let width = 0;
        let height = 0;

        const resize = () => {
            const el = containerRef.current;
            if (!el) return;
            width = el.clientWidth;
            height = el.clientHeight;
            const dpr = window.devicePixelRatio || 1;

            canvas.width = width * dpr;
            canvas.height = height * dpr;
            canvas.style.width = `${width}px`;
            canvas.style.height = `${height}px`;
            ctx.scale(dpr, dpr);

            // Initialize particles to center screen
            particlesRef.current.forEach(p => {
                p.x = width / 2;
                p.y = height / 2;
            });
        };

        const resizeObserver = new ResizeObserver(() => resize());
        if (containerRef.current) resizeObserver.observe(containerRef.current);
        resize();

        let animationFrameId: number;

        const drawBars = (data: Uint8Array, sens: number) => {
            const barWidth = width / data.length;
            for (let i = 0; i < data.length; i++) {
                const val = data[i] * sens;
                const percent = val / 255;
                const h = height * percent;

                // Hue shifts from blue (bass) to pink (treble)
                const hue = 220 + (i / data.length) * 100;
                ctx.fillStyle = `hsl(${hue}, 80%, 50%)`;

                // Draw mirrored from center vertically
                ctx.fillRect(i * barWidth, height / 2 - h / 2, barWidth - 1, h);
            }
        };

        const drawRings = (data: Uint8Array, timeData: Uint8Array, sens: number) => {
            const cx = width / 2;
            const cy = height / 2;
            const baseRadius = Math.min(width, height) * 0.2;

            ctx.beginPath();
            for (let i = 0; i < data.length; i++) {
                // How far around the circle are we? (0 to 2PI)
                const angle = (i / data.length) * Math.PI * 2;

                // Offset the radius by both frequency intensity and time domain waveform
                const freqVal = data[i] * sens;
                const waveVal = (timeData[i] - 128) * sens; // Time domain is centered on 128

                // Add a smooth easing so the circle connects seamlessly
                const r = baseRadius + (freqVal * 0.5) + waveVal;

                const x = cx + Math.cos(angle) * r;
                const y = cy + Math.sin(angle) * r;

                if (i === 0) ctx.moveTo(x, y);
                else ctx.lineTo(x, y);
            }
            ctx.closePath();

            // Calculate total volume for color shift
            const totalVol = data.reduce((a, b) => a + b, 0) / data.length;
            const hue = 200 + totalVol * sens;

            ctx.strokeStyle = `hsl(${hue}, 90%, 60%)`;
            ctx.lineWidth = 3;
            ctx.stroke();

            ctx.fillStyle = `hsla(${hue}, 90%, 60%, 0.1)`;
            ctx.fill();
        };

        const drawParticles = (data: Uint8Array, sens: number) => {
            // Find rough bass and treble averages
            let bass = 0, treble = 0;
            const third = Math.floor(data.length / 3);

            for (let i = 0; i < third; i++) bass += data[i];
            for (let i = data.length - third; i < data.length; i++) treble += data[i];

            bass = (bass / third) * sens;
            treble = (treble / third) * sens;

            const cx = width / 2;
            const cy = height / 2;
            const particles = particlesRef.current;

            for (let i = 0; i < particles.length; i++) {
                const p = particles[i];

                // Bass pushes particles outwards, Treble makes them jiggle and spin faster
                const outwardPush = (bass / 255) * 5;
                const spin = p.baseSpeed + ((treble / 255) * 10);

                p.angle += spin * 0.01;

                // Vector to center
                const dx = p.x - cx;
                const dy = p.y - cy;
                const dist = Math.sqrt(dx * dx + dy * dy) || 1;

                // Apply forces
                p.vx += (dx / dist) * outwardPush;
                p.vy += (dy / dist) * outwardPush;

                // Add Gravity pulling towards center
                p.vx -= (dx / dist) * 2;
                p.vy -= (dy / dist) * 2;

                // Add orbital spin based on angle
                p.vx += Math.cos(p.angle) * spin;
                p.vy += Math.sin(p.angle) * spin;

                // Friction
                p.vx *= 0.85;
                p.vy *= 0.85;

                p.x += p.vx;
                p.y += p.vy;

                // Draw
                // Particle expands on bass
                const size = p.size + (bass / 255) * 10;
                ctx.fillStyle = p.color;
                ctx.globalAlpha = 0.6 + (treble / 255) * 0.4;

                ctx.beginPath();
                ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
                ctx.fill();
            }
        };

        const render = () => {
            // 1. Fetch Audio Data
            if (analyserRef.current) {
                // @ts-expect-error: Next.js strict lib.dom types clash with standard Uint8Array
                analyserRef.current.getByteFrequencyData(audioBoxRef.current.frequencyData);
                // @ts-expect-error
                analyserRef.current.getByteTimeDomainData(audioBoxRef.current.timeDomainData);
            }

            const freqData = audioBoxRef.current.frequencyData;
            const timeData = audioBoxRef.current.timeDomainData;

            // 2. Clear Canvas
            // In Particles mode, use a fade clear for trails. Draw instant black for others.
            if (props.visualStyle === 'particles') {
                ctx.fillStyle = "rgba(9, 9, 11, 0.2)"; // zinc-950 with trail fade
            } else {
                ctx.fillStyle = "#09090b"; // zinc-950 solid
            }
            ctx.globalAlpha = 1;
            ctx.globalCompositeOperation = "source-over"; // Reset composite
            ctx.fillRect(0, 0, width, height);

            // Make visuals pop brightly with additive blending
            ctx.globalCompositeOperation = "lighter";

            // 3. Render appropriate style
            // We only render if there's actually audio data, OR if we strictly want drawing to continue (particles always move)
            if (freqData.length > 0 || props.visualStyle === 'particles') {
                if (props.visualStyle === 'bars') drawBars(freqData, props.sensitivity);
                else if (props.visualStyle === 'rings') drawRings(freqData, timeData, props.sensitivity);
                else if (props.visualStyle === 'particles') drawParticles(freqData, props.sensitivity);
            }

            animationFrameId = requestAnimationFrame(render);
        };

        // Kickoff loop
        animationFrameId = requestAnimationFrame(render);

        return () => {
            resizeObserver.disconnect();
            cancelAnimationFrame(animationFrameId);
        };
    }, [props.visualStyle, props.sensitivity]); // Deliberately omitting arrays or isListening to prevent stutter

    return (
        <div
            ref={containerRef}
            className="w-full h-full min-h-[400px] bg-zinc-950 rounded-2xl border border-zinc-800 overflow-hidden relative shadow-lg"
        >
            <canvas
                ref={canvasRef}
                className="block w-full h-full touch-none"
            />
        </div>
    );
}

"use client";

import React, { useRef, useEffect } from "react";
import { SimulationConfig, GlobalSettings, Ball, Vector2 } from "@/lib/physics/ai-simulator-presets";
import { generatePolygon, generateStar, add, mult, dot, sub, normalize, mag } from "@/lib/physics/ai-simulator-math";

interface PhysicsCanvasProps {
    config: SimulationConfig;
    globalSettings: GlobalSettings;
}

export function PhysicsCanvas({ config, globalSettings }: PhysicsCanvasProps) {
    const containerRef = useRef<HTMLDivElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const requestRef = useRef<number | null>(null);
    const stateRef = useRef<{
        balls: Ball[];
        rotation: number;
        width: number;
        height: number;
        dpr: number;
    }>({
        balls: [],
        rotation: 0,
        width: 0,
        height: 0,
        dpr: 1
    });

    // Re-Initialize Simulation when config or ball properties change
    useEffect(() => {
        const balls: Ball[] = [];
        const count = Math.floor(config.ballCount);

        for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const dist = Math.random() * 30; // Spawn near center
            const speed = config.initialSpeed * (0.5 + Math.random());
            const velAngle = Math.random() * Math.PI * 2;

            // HSL color palette ranging from Blue to Cyan/Teal
            const hue = 190 + Math.random() * 40;

            balls.push({
                id: `${config.id}-${i}`,
                pos: { x: Math.cos(angle) * dist, y: Math.sin(angle) * dist }, // Relative to center 0,0
                vel: { x: Math.cos(velAngle) * speed, y: Math.sin(velAngle) * speed },
                radius: config.ballSize,
                color: `hsl(${hue}, 80%, 60%)`,
            });
        }

        stateRef.current.balls = balls;
        stateRef.current.rotation = 0;
    }, [config.id, config.ballCount, config.initialSpeed, config.ballSize]);

    // Main tick loop
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d', { alpha: false });
        if (!ctx) return;

        const resize = () => {
            const el = containerRef.current;
            if (!el) return;
            const width = el.clientWidth;
            const height = el.clientHeight;
            const dpr = window.devicePixelRatio || 1;

            if (stateRef.current.width !== width || stateRef.current.height !== height || stateRef.current.dpr !== dpr) {
                canvas.width = width * dpr;
                canvas.height = height * dpr;
                canvas.style.width = `${width}px`;
                canvas.style.height = `${height}px`;

                stateRef.current.width = width;
                stateRef.current.height = height;
                stateRef.current.dpr = dpr;
            }
        };

        const resizeObserver = new ResizeObserver(() => resize());
        if (containerRef.current) resizeObserver.observe(containerRef.current);
        resize();

        const updatePhysics = (width: number, height: number, dpr: number) => {
            const state = stateRef.current;
            const { gravityMultiplier, timeScale, rotationMultiplier, bouncinessMultiplier } = globalSettings;

            const shapeRadius = Math.min(width, height) * 0.40;

            // 1. Update Rotation
            state.rotation += config.rotationSpeed * rotationMultiplier * timeScale;

            // 2. Generate Shape Vertices (Local Space around 0,0)
            let localVertices: Vector2[] = [];
            if (config.shapeType === 'star') {
                localVertices = generateStar(config.vertexCount || 5, shapeRadius, shapeRadius * 0.4, { x: 0, y: 0 }, state.rotation);
            } else {
                localVertices = generatePolygon(config.vertexCount || 4, shapeRadius, { x: 0, y: 0 }, state.rotation);
            }

            // 3. Update Balls
            state.balls.forEach(ball => {
                // Apply Forces & Velocity
                ball.vel.y += config.gravity * gravityMultiplier * timeScale;
                ball.vel = mult(ball.vel, 1 - config.friction * timeScale);
                ball.pos = add(ball.pos, mult(ball.vel, timeScale));

                // Collision with Container Walls
                const restitution = config.restitution * bouncinessMultiplier;

                for (let i = 0; i < localVertices.length; i++) {
                    const p1 = localVertices[i];
                    const p2 = localVertices[(i + 1) % localVertices.length];
                    const edge = sub(p2, p1);

                    // Calculate normal pointing inward
                    const edgeNormal = normalize({ x: -edge.y, y: edge.x });
                    if (dot(edgeNormal, mult(p1, -1)) < 0) {
                        edgeNormal.x *= -1;
                        edgeNormal.y *= -1;
                    }

                    const relPos = sub(ball.pos, p1);
                    const dist = dot(relPos, edgeNormal);

                    if (dist < ball.radius) {
                        // Position correction (push it strictly out of the wall)
                        const penetration = ball.radius - dist;
                        ball.pos = add(ball.pos, mult(edgeNormal, penetration));

                        // Reflect Velocity
                        const velDotNormal = dot(ball.vel, edgeNormal);
                        if (velDotNormal < 0) {
                            const reflect = mult(edgeNormal, 2 * velDotNormal);
                            ball.vel = sub(ball.vel, mult(reflect, 1));
                            ball.vel = mult(ball.vel, restitution);
                            // Tiny push to prevent sticking to the line perfectly
                            ball.vel = add(ball.vel, mult(edgeNormal, 0.1));
                        }
                    }
                }
            });

            // 4. Ball-to-Ball Collisions
            const balls = state.balls;
            for (let i = 0; i < balls.length; i++) {
                for (let j = i + 1; j < balls.length; j++) {
                    const ballA = balls[i];
                    const ballB = balls[j];

                    const distVec = sub(ballB.pos, ballA.pos);
                    const distance = mag(distVec);
                    const totalRadius = ballA.radius + ballB.radius;

                    if (distance < totalRadius) {
                        // Collision detected! Position Correction (push apart)
                        const overlap = totalRadius - distance;
                        const correctionNormal = distance === 0 ? { x: 1, y: 0 } : normalize(distVec);
                        const correctionA = mult(correctionNormal, -overlap / 2);
                        const correctionB = mult(correctionNormal, overlap / 2);
                        ballA.pos = add(ballA.pos, correctionA);
                        ballB.pos = add(ballB.pos, correctionB);

                        // Velocity Update (elastic collision swapping momentum)
                        const collisionNormal = normalize(distVec);
                        const relativeVelocity = sub(ballB.vel, ballA.vel);
                        const speedAlongNormal = dot(relativeVelocity, collisionNormal);

                        // Only resolve if balls are actually moving towards each other
                        if (speedAlongNormal < 0) {
                            const v1n_scalar = dot(ballA.vel, collisionNormal);
                            const v2n_scalar = dot(ballB.vel, collisionNormal);

                            const v1n_vec = mult(collisionNormal, v1n_scalar);
                            const v2n_vec = mult(collisionNormal, v2n_scalar);

                            const v1t_vec = sub(ballA.vel, v1n_vec);
                            const v2t_vec = sub(ballB.vel, v2n_vec);

                            // Swap normal components
                            ballA.vel = add(v1t_vec, v2n_vec);
                            ballB.vel = add(v2t_vec, v1n_vec);
                        }
                    }
                }
            }

            // 5. Bounds Safefall (reset if ball escapes the polygon bounds entirely)
            balls.forEach(ball => {
                if (mag(ball.pos) > shapeRadius + 150) {
                    ball.pos = { x: 0, y: 0 };
                    ball.vel = { x: 0, y: 0 };
                }
            });
        };

        const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, dpr: number) => {
            // Reset transform to draw background
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

            ctx.fillStyle = "#09090b"; // zinc-950
            ctx.fillRect(0, 0, width, height);

            const center = { x: width / 2, y: height / 2 };
            const state = stateRef.current;
            const shapeRadius = Math.min(width, height) * 0.40;

            // Draw Polygon Shape Outline
            let points: Vector2[] = [];
            if (config.shapeType === 'star') {
                points = generateStar(config.vertexCount || 5, shapeRadius, shapeRadius * 0.4, center, state.rotation);
            } else {
                points = generatePolygon(config.vertexCount || 4, shapeRadius, center, state.rotation);
            }

            ctx.beginPath();
            if (points.length > 0) {
                ctx.moveTo(points[0].x, points[0].y);
                for (let i = 1; i < points.length; i++) {
                    ctx.lineTo(points[i].x, points[i].y);
                }
                ctx.closePath();
            }

            ctx.strokeStyle = '#3b82f6'; // blue-500
            ctx.lineWidth = 3;
            ctx.lineJoin = 'round';
            ctx.stroke();

            ctx.fillStyle = 'rgba(59, 130, 246, 0.05)';
            ctx.fill();

            // Draw Balls
            state.balls.forEach(ball => {
                const screenX = center.x + ball.pos.x;
                const screenY = center.y + ball.pos.y;

                ctx.beginPath();
                ctx.arc(screenX, screenY, ball.radius, 0, Math.PI * 2);
                ctx.fillStyle = ball.color;
                ctx.fill();
            });
        };

        const tick = () => {
            const state = stateRef.current;
            if (state.width > 0 && state.height > 0) {
                updatePhysics(state.width, state.height, state.dpr);
                draw(ctx, state.width, state.height, state.dpr);
            }
            requestRef.current = requestAnimationFrame(tick);
        };

        requestRef.current = requestAnimationFrame(tick);

        return () => {
            resizeObserver.disconnect();
            if (requestRef.current) cancelAnimationFrame(requestRef.current);
        };
    }, [config, globalSettings]);

    return (
        <div
            ref={containerRef}
            className="w-full h-full min-h-[400px] bg-zinc-950 rounded-2xl border border-zinc-800 overflow-hidden relative shadow-[0_0_40px_rgba(0,0,0,0.5)] cursor-crosshair"
        >
            <canvas
                ref={canvasRef}
                className="block w-full h-full touch-none"
            />
        </div>
    );
}

import { useEffect, useRef, useState } from 'react';

// Expose the raw data arrays directly instead of returning them in React State
// Returning 1024-length arrays in React State 60 times a second will destroy performance.
// React components will just read from the ref directly inside their own requestAnimationFrame
export interface AudioDataBox {
    frequencyData: Uint8Array;
    timeDomainData: Uint8Array;
}

export function useAudioAnalyser(isListening: boolean, smoothingTimeConstant: number) {
    const audioContextRef = useRef<AudioContext | null>(null);
    const analyserRef = useRef<AnalyserNode | null>(null);
    const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
    const streamRef = useRef<MediaStream | null>(null);

    // This is the mutable box we will read from inside Canvas loops
    const dataBoxRef = useRef<AudioDataBox>({
        frequencyData: new Uint8Array(0),
        timeDomainData: new Uint8Array(0),
    });

    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        let mounted = true;

        const startAudio = async () => {
            try {
                // Initialize Web Audio API
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
                const audioCtx = new AudioContext();
                audioContextRef.current = audioCtx;

                // Request microphone access
                const stream = await navigator.mediaDevices.getUserMedia({
                    audio: {
                        echoCancellation: false,
                        autoGainControl: false,
                        noiseSuppression: false,
                    }
                });

                if (!mounted) {
                    stream.getTracks().forEach(track => track.stop());
                    return;
                }

                streamRef.current = stream;

                // Create Analyser
                const analyser = audioCtx.createAnalyser();
                // fftSize dictates the resolution of our frequency data.
                // 1024 means we get 512 frequency bins back.
                analyser.fftSize = 1024;
                analyser.smoothingTimeConstant = smoothingTimeConstant;
                analyserRef.current = analyser;

                // Connect Microphone to Analyser (We DO NOT connect analyser to destination or it will feedback loop)
                const source = audioCtx.createMediaStreamSource(stream);
                source.connect(analyser);
                sourceRef.current = source;

                // Setup the data arrays for the ref box
                dataBoxRef.current.frequencyData = new Uint8Array(analyser.frequencyBinCount);
                dataBoxRef.current.timeDomainData = new Uint8Array(analyser.frequencyBinCount);

                setError(null);
            } catch (err) {
                console.error("Failed to initialize audio:", err);
                setError(err instanceof Error ? err.message : "Failed to access microphone");
            }
        };

        const stopAudio = () => {
            if (streamRef.current) {
                streamRef.current.getTracks().forEach(t => t.stop());
                streamRef.current = null;
            }
            if (sourceRef.current) {
                sourceRef.current.disconnect();
                sourceRef.current = null;
            }
            if (audioContextRef.current) {
                audioContextRef.current.close().catch(console.error);
                audioContextRef.current = null;
            }
            analyserRef.current = null;

            // Zero out data
            if (dataBoxRef.current.frequencyData.length > 0) {
                dataBoxRef.current.frequencyData.fill(0);
                dataBoxRef.current.timeDomainData.fill(128); // Time domain centers at 128
            }
        };

        if (isListening) {
            startAudio();
        } else {
            stopAudio();
        }

        return () => {
            mounted = false;
            stopAudio();
        };
    }, [isListening]);

    // Update smoothing dynamically without restarting stream
    useEffect(() => {
        if (analyserRef.current) {
            analyserRef.current.smoothingTimeConstant = smoothingTimeConstant;
        }
    }, [smoothingTimeConstant]);

    // This function will be called by requestAnimationFrame inside our Canvas
    const getAudioData = () => {
        const analyser = analyserRef.current;
        const box = dataBoxRef.current;

        if (analyser && box.frequencyData.length > 0) {
            // @ts-ignore
            analyser.getByteFrequencyData(box.frequencyData);
            // @ts-ignore
            analyser.getByteTimeDomainData(box.timeDomainData);
        }

        return box;
    };

    return { getAudioData, error };
}

